Rules.InvariantScript:
UpdateContext(
    {
        locLoadingText: "Downloading job...",
        locLoadingPercent: 0
    }
);
If(
    gblAppAutoload,
    Select(btn_LoadJob_LoadCdsUser)
);

Table(
    {
        tblCount: CountRows(colCdsJobs),
        tblName: "localCdsJobs"
    },
    {
        tblCount: CountRows(colCdsJobEntries),
        tblName: "localCdsJobEntries"
    },
    {
        tblCount: CountRows(colCdsJobEntrySelections),
        tblName: "localCdsJobEntrySelections"
    },
    {
        tblCount: CountRows(colCdsWindowMeasurements),
        tblName: "localCdsWindowMeasurements"
    },
    {
        tblCount: CountRows(colCdsRooms),
        tblName: "localCdsRooms"
    },
    {
        tblCount: CountRows(colCdsWindowModels),
        tblName: "localCdsWindowModels"
    },
    {
        tblCount: CountRows(colCdsWindowChoices),
        tblName: "localCdsWindowChoices"
    },
    {
        tblCount: CountRows(colCdsJobStages),
        tblName: "localCdsJobStages"
    },
    {
        tblCount: CountRows(colCdsWindowStyles),
        tblName: "localCdsWindowStyles"
    },
    {
        tblCount: CountRows(colCdsMarketSegments),
        tblName: "localCdsMarketSegments"
    },
    {
        tblCount: CountRows(colCdsAccounts),
        tblName: "localCdsAccounts"
    },
    {
        tblCount: CountRows(colCdsWindowMulls),
        tblName: "localCdsWindowMulls"
    },
    {
        tblCount: CountRows(colCdsJobRooms),
        tblName: "localCdsJobRooms"
    },
    {
        tblCount: CountRows(colCdsLaborItems),
        tblName: "localCdsLaborItems"
    },
    {
        tblCount: CountRows(colCdsMarketLaborItems),
        tblName: "localCdsMarketLaborItems"
    },
    {
        tblCount: CountRows(colCdsJobLaborItems),
        tblName: "localCdsJobLaborItems"
    },
    {
        tblCount: CountRows(colCdsMaterialItems),
        tblName: "localCdsMaterialItems"
    },
    {
        tblCount: CountRows(colCdsMarketMaterialItems),
        tblName: "localCdsMarketMaterialItems"
    },
    {
        tblCount: CountRows(colCdsJobMaterialItems),
        tblName: "localCdsJobMaterialItems"
    },
    {
        tblCount: CountRows(colCdsDocuments),
        tblName: "localCdsDocuments"
    },
    {
        tblCount: CountRows(colCdsJobDocuments),
        tblName: "localCdsJobDocuments"
    },
    {
        tblCount: CountRows(colCdsJobEntryOptions),
        tblName: "localCdsJobEntryOptions"
    }
)

Trace("Button Pressed: Loading Step 1",TraceSeverity.Information);
UpdateContext(
    {
        locLoadingText: "Load Job Data...",
        locLoadingPercent: 30
    }
);
Concurrent(
// JOB DOCUMENTS
    Collect(
        colCdsJobDocuments,
        AddColumns(
            Filter(
                'Job Documents',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobDocument.Status.Active
            ),
            appJobIdText,
            Text(Job.Job),
            appJobDocumentIdText,
            Text('Job Document')
        )
    ),
// JOB ENTRIES
    Collect(
        colCdsJobEntries,
        AddColumns(
            Filter(
                'Job Entries',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobEntry.Status.Active
            ),
            appFields,
            Concatenate(
                "",
                Job.Name
            ),
            appJobRoomIdText,
            Text('Job Room'.'Job Room'),
            appJobIdText,
            Text(Job.Job),
            '''Window Choice''',
            'Window Choice'
        )
    ),
// JOB ENTRY SELECTIONS
    Collect(
        colCdsJobEntrySelections,
        AddColumns(
            Filter(
                'Job Entry Selections',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobEntrySelection.Status.Active
            ),
            appAttributeName,
            'Job Entry Option (Attribute)'.Name
        )
    ),
// JOB LABOR ITEMS
    Collect(
        colCdsJobLaborItems,
        AddColumns(
            Filter(
                'Job Labor Items',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobLaborItem.Status.Active
            ),
            appJobIDText,
            Text(Job.Job)
        )
    ),
// JOB MATERIAL ITEMS
    Collect(
        colCdsJobMaterialItems,
        AddColumns(
            Filter(
                'Job Material Items',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobMaterialItem.Status.Active
            ),
            appJobIDText,
            Text(Job.Job)
        )
    ),
// JOB PHOTOS
    Collect(
        colCdsJobPhotos,
        Filter(
            'Job Photos',
            Job.Job = gblRecordJobCurrent.Job,
            Status = gblOptionSets.JobPhoto.Status.Active
        )
    ),
// JOB ROOMS
    Collect(
        colCdsJobRooms,
        AddColumns(
            Filter(
                'Job Rooms',
                Job.Job = gblRecordJobCurrent.Job,
                Status = gblOptionSets.JobRoom.Status.Active
            ),
            appJobRoomIdText,
            Text('Job Room'),
            appJobIdText,
            Text(Job.Job)
        )
    ),
    // MARKET LABOR ITEMS
    If(
        IsBlank(
            LookUp(
                colCdsMarketLaborItems,
                'Market Segment'.'Market Segment' = gblRecordJobCurrent.'Market Segment'.'Market Segment'
            )
        ),
        Collect(
            colCdsMarketLaborItems,
            AddColumns(
                Filter(
                    'Market Labor Items',
                    'Market Segment'.'Market Segment' = gblRecordJobCurrent.'Market Segment'.'Market Segment'
                ),
                appMarketSegment,
                'Market Segment'.'Market Segment',
                appLaborDisplayOrder,
                'Labor Item'.'Display Order'
            )
        )
    ),
    // MARKET MATERIAL ITEMS
    If(
        IsBlank(
            LookUp(
                colCdsMarketMaterialItems,
                'Market Segment'.'Market Segment' = gblRecordJobCurrent.'Market Segment'.'Market Segment'
            )
        ),
        Collect(
            colCdsMarketMaterialItems,
            AddColumns(
                Filter(
                    'Market Material Items',
                    'Market Segment'.'Market Segment' = gblRecordJobCurrent.'Market Segment'.'Market Segment'
                ),
                appMarketSegment,
                'Market Segment'.'Market Segment',
                appMaterialName,
                'Material Item'.Name
            )
        )
    ),
// WINDOW MEASUREMENTS
    Collect(
        colCdsWindowMeasurements,
        Filter(
            'Window Measurements',
            Job.Job = gblRecordJobCurrent.Job,
            Status = gblOptionSets.WindowMeasurement.Status.Active
        )
    ),
// WINDOW MULLS
    Collect(
        colCdsWindowMulls,
        AddColumns(
            Filter(
                'Window Mulls',
                Job.Job = gblRecordJobCurrent.Job
            ),
            appJobRoomIdText,
            Text('Job Room'.'Job Room')
        )
    )
);
With(
    {
        varType: "colCdsJobs",
        varRecordRef: gblRecordJobCurrent.Job
    },
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    )
);
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Save Job Data...",
            locLoadingPercent: 60
        }
    );
    Select(btn_LoadJob_SaveLocalFiles);
);

Trace(
    "Button Pressed: Loading Step 2",
    TraceSeverity.Information
);
If(
    gblAppLoadOffline,
// JOB DOCUMENTS
    SaveData(
        colCdsJobDocuments,
        "localCdsJobDocuments"
    );

// JOB ENTRIES
SaveData(
        colCdsJobEntries,
        "localCdsJobEntries"
    );

// JOB ENTRY SELECTIONS
SaveData(
        colCdsJobEntrySelections,
        "localCdsJobEntrySelections"
    );

// JOB LABOR ITEMS
SaveData(
        colCdsJobLaborItems,
        "localCdsJobLaborItems"
    );

// JOB MATERIAL ITEMS
SaveData(
        colCdsJobMaterialItems,
        "localCdsJobMaterialItems"
    );

// MARKET LABOR ITEMS
SaveData(
        colCdsMarketLaborItems,
        "localCdsMarketLaborItems"
    );

// MARKET MATERIAL ITEMS
SaveData(
        colCdsMarketMaterialItems,
        "localCdsMarketMaterialItems"
    );

// JOB PHOTOS
SaveData(
        colCdsJobPhotos,
        "localCdsJobPhotos"
    );

// JOB ROOMS
SaveData(
        colCdsJobRooms,
        "localCdsJobRooms"
    );

// JOBS
SaveData(
        colCdsJobs,
        "localCdsJobs"
    );

// WINDOW MEASUREMENTS
SaveData(
        colCdsWindowMeasurements,
        "localCdsWindowMeasurements"
    );

// WINDOW MULLS
SaveData(
        colCdsWindowMulls,
        "localCdsWindowMulls"
    );

);
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Loading Job Entry Options...",
            locLoadingPercent: 75
        }
    );
    Select(btn_LoadJob_LoadJobEntryOptions)
);

Trace(
    "Button Pressed: Loading 3",
    TraceSeverity.Information
);
// Get list of unique window choices for any jobs currently on the device
ClearCollect(
    colWindowChoices_ForJobsOnDevice,
    Distinct(
        AddColumns(
            colCdsJobEntries,
            WindowChoiceID,
            'Window Choice'.'Window Choice'
        ).WindowChoiceID,
        WindowChoiceID
    )
);
// Add a column for the job entry option headers to the window choices
ClearCollect(
    colJobEntryOptionHeaders_ForJobsOnDevice,
    Distinct(
        AddColumns(
            colWindowChoices_ForJobsOnDevice,
            HeaderID,
            LookUp(
                colCdsWindowChoices,
                'Window Choice' = Value,
                'Job Entry Option (Header)'
            ).'Job Entry Option'
        ).HeaderID,
        HeaderID
    )
);
// Determine whether a new set of Job Entry Options must be downloaded to the device
Set(
    gblShouldAppDownloadJobEntryOptions,
    false in AddColumns(
        colJobEntryOptionHeaders_ForJobsOnDevice,
        OnDevice,
        Value in colCdsJobEntryOptions.'Job Entry Option'
    ).OnDevice
);
// Loop through each column header and download its child options
If(
    gblShouldAppDownloadJobEntryOptions,
    ForAll(
        Filter(
            colJobEntryOptionHeaders_ForJobsOnDevice,
            !(Value in colCdsJobEntryOptions.'Job Entry Option')
        ) As currentRecord,
        // Get header record
        Collect(
            colCdsJobEntryOptions,
            Filter(
                'Job Entry Options',
                'Job Entry Option'=currentRecord.Value,
                Status=gblOptionSets.JobEntryOption.Status.Active,
                'Legacy?'=gblOptionSets.JobEntryOption.IsLegacy.No
            )
        );
        // Get attributes, hierarchy steps and values
        Collect(
            colCdsJobEntryOptions,
            Filter(
                'Job Entry Options',
                'Job Entry Option (Header Root)'.'Job Entry Option'=currentRecord.Value,
                Status=gblOptionSets.JobEntryOption.Status.Active,
                'Legacy?'=gblOptionSets.JobEntryOption.IsLegacy.No
            )
        )
    );
    UpdateContext({locSaveJobEntryOptions: true});
);
Clear(colWindowChoices_ForJobsOnDevice);
Clear(colJobEntryOptionHeaders_ForJobsOnDevice);
Set(gblShouldAppDownloadJobEntryOptions, false);
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Saving Job Entry Options...",
            locLoadingPercent: 90
        }
    );
    Select(btn_LoadJob_SaveCdsOrg_Options)
);

Trace(
    "Button Pressed: Loading 4",
    TraceSeverity.Information
);
// JOB ENTRY OPTIONS
If(
    locSaveJobEntryOptions And gblAppLoadOffline,
    ClearCollect(
        colStagingCdsJobEntryOptions_Header,
        Filter(
            colCdsJobEntryOptions,
            Type = gblOptionSets.JobEntryOption.Type.Header
        )
    );
    SaveData(
        colStagingCdsJobEntryOptions_Header,
        "localCdsJobEntryOptions_Header"
    );
    ClearCollect(
        colStagingCdsJobEntryOptions_Attribute,
        Filter(
            colCdsJobEntryOptions,
            Type = gblOptionSets.JobEntryOption.Type.Attribute
        )
    );
    SaveData(
        colStagingCdsJobEntryOptions_Attribute,
        "localCdsJobEntryOptions_Attribute"
    );
    ClearCollect(
        colStagingCdsJobEntryOptions_HierarchyStep,
        Filter(
            colCdsJobEntryOptions,
            Type = gblOptionSets.JobEntryOption.Type.HierarchyStep
        )
    );
    SaveData(
        colStagingCdsJobEntryOptions_HierarchyStep,
        "localCdsJobEntryOptions_HierarchyStep"
    );
    ClearCollect(
        colStagingCdsJobEntryOptions_Value,
        Filter(
            colCdsJobEntryOptions,
            Type = gblOptionSets.JobEntryOption.Type.Value
        )
    );
    SaveData(
        colStagingCdsJobEntryOptions_Value,
        "localCdsJobEntryOptions_Value"
    )
);
UpdateContext({locSaveJobEntryOptions: false});
If(
    gblAppAutoAdvance,
    UpdateContext(
        {
            locLoadingText: "Loading Completed!",
            locLoadingPercent: 100
        }
    );
    Select(btn_LoadJob_Proceed)
)

Trace(
    "Button Pressed: Loading Step 5",
    TraceSeverity.Information
);
If(
    // go to rooms screen
    gblTextClickedSaveScreen = "Rooms Screen",
    Navigate(
        'Rooms Screen',
        ScreenTransition.Fade
    ),
    // go to final steps screen
    gblTextClickedSaveScreen = "Final Steps Screen",
    Navigate(
        'Final Steps Screen',
        ScreenTransition.Fade
    ),
    // fall back screen when gblTextClickedSaveScreen is blank
    Navigate(
        'Job Details Screen',
        ScreenTransition.Fade,
        {
            locReOpenClosedJobDecisionMade: false,
            locCurrentJobDetailsPage: 1
        }
    )
);

With(
    {varWidth: shp_Loading_ProgressBackground_1.Width},
    varWidth * locLoadingPercent/100
)
